import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { obtenerFicha, guardarFicha } from '../service/api';

const TABS = ['Datos personales', 'Datos físicos', 'Información médica', 'Emergencia'];

export default function PerfilPage() {
  const { usuario } = useAuth();
  const p = usuario?.persona;
  const [tab, setTab] = useState(0);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [exito, setExito] = useState('');
  const [error, setError] = useState('');

  const [ficha, setFicha] = useState({
    telefono: '', direccion: '',
    estatura: '', peso: '', grupoSanguineo: '', presionArterial: '', frecuenciaCardiaca: '', glucosa: '',
    alergias: '', condicionesCronicas: '', medicamentosActuales: '', cirugiasPrevias: '', antecedentesFamiliares: '',
    habitoTabaco: 'No fumador', habitoAlcohol: 'No consume',
    emergenciaNombre: '', emergenciaTelefono: '', emergenciaRelacion: 'Familiar',
  });

  useEffect(() => {
    if (!usuario?.id) return;
    obtenerFicha(usuario.id).then(data => {
      if (data) setFicha({ ...ficha, ...data });
    }).finally(() => setLoading(false));
  }, [usuario]);

  const set = k => e => setFicha({ ...ficha, [k]: e.target.value });

  const handleGuardar = async () => {
    setSaving(true); setExito(''); setError('');
    try {
      await guardarFicha(usuario.id, ficha);
      setExito('✅ Datos guardados correctamente.');
    } catch { setError('❌ Error al guardar. Intenta de nuevo.');
    } finally { setSaving(false); }
  };

  const imc = ficha.estatura && ficha.peso
    ? (ficha.peso / ((ficha.estatura / 100) ** 2)).toFixed(1)
    : null;

  const imcLabel = imc
    ? imc < 18.5 ? 'Bajo peso' : imc < 25 ? 'Normal' : imc < 30 ? 'Sobrepeso' : 'Obesidad'
    : null;

  const iniciales = p ? (p.apellido1?.[0] || '') + (p.apellido2?.[0] || '') : usuario?.mail?.[0]?.toUpperCase() || '?';

  if (loading) return <div className="spinner">Cargando perfil...</div>;

  return (
    <div className="page" style={{ maxWidth: 700 }}>
      <h2 className="page-title">👤 Mi perfil</h2>

      {exito && <div className="alert alert-success">{exito}</div>}
      {error  && <div className="alert alert-error">{error}</div>}

      {/* Avatar */}
      <div className="card" style={{ textAlign: 'center', marginBottom: 20, padding: 28 }}>
        <div style={{
          width: 72, height: 72, borderRadius: '50%',
          background: 'linear-gradient(135deg, var(--primary), var(--teal))',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          margin: '0 auto 12px', fontSize: 28, color: 'white', fontWeight: 700
        }}>{iniciales}</div>
        <h3 style={{ fontSize: 20, marginBottom: 4 }}>
          {p ? `${p.apellido1} ${p.apellido2 || ''}` : 'Paciente'}
        </h3>
        <div style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 8 }}>{usuario?.mail}</div>
        <span style={{ background: 'var(--primary-light)', color: 'var(--primary)', borderRadius: 20, padding: '3px 14px', fontSize: 12, fontWeight: 600 }}>
          {usuario?.rol?.nombre || 'Paciente'}
        </span>
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: 4, marginBottom: 20, borderBottom: '1px solid var(--border)', paddingBottom: 0 }}>
        {TABS.map((t, i) => (
          <button key={t} onClick={() => setTab(i)} style={{
            padding: '8px 16px', border: 'none', background: 'transparent', cursor: 'pointer',
            fontSize: 14, fontWeight: tab === i ? 600 : 400,
            color: tab === i ? 'var(--primary)' : 'var(--text-muted)',
            borderBottom: tab === i ? '2px solid var(--primary)' : '2px solid transparent',
            marginBottom: -1,
          }}>{t}</button>
        ))}
      </div>

      <div className="card">

        {/* TAB 0: Datos personales */}
        {tab === 0 && (
          <>
            <div className="grid-2" style={{ marginBottom: 16 }}>
              <div className="form-group">
                <label>Primer apellido</label>
                <input className="form-control" value={p?.apellido1 || ''} disabled style={{ opacity: 0.6 }} />
              </div>
              <div className="form-group">
                <label>Segundo apellido</label>
                <input className="form-control" value={p?.apellido2 || ''} disabled style={{ opacity: 0.6 }} />
              </div>
              <div className="form-group">
                <label>RUT</label>
                <input className="form-control" value={p?.rut || ''} disabled style={{ opacity: 0.6 }} />
              </div>
              <div className="form-group">
                <label>Fecha de nacimiento</label>
                <input className="form-control" value={p?.fechaNacimiento || ''} disabled style={{ opacity: 0.6 }} />
              </div>
              <div className="form-group">
                <label>Sexo</label>
                <input className="form-control" value={p?.sexo === 'M' ? 'Masculino' : p?.sexo === 'F' ? 'Femenino' : p?.sexo || ''} disabled style={{ opacity: 0.6 }} />
              </div>
              <div className="form-group">
                <label>Correo electrónico</label>
                <input className="form-control" value={usuario?.mail || ''} disabled style={{ opacity: 0.6 }} />
              </div>
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label>Teléfono</label>
                <input className="form-control" value={ficha.telefono} onChange={set('telefono')} placeholder="+56 9 1234 5678" />
              </div>
              <div className="form-group">
                <label>Dirección</label>
                <input className="form-control" value={ficha.direccion} onChange={set('direccion')} placeholder="Calle, número, ciudad" />
              </div>
            </div>
            <div className="alert alert-info" style={{ marginTop: 8 }}>
              💡 Los datos con fondo gris son administrados por el sistema. Contacta al administrador para modificarlos.
            </div>
          </>
        )}

        {/* TAB 1: Datos físicos */}
        {tab === 1 && (
          <>
            <div className="grid-2" style={{ marginBottom: 16 }}>
              <div className="form-group">
                <label>Estatura (cm)</label>
                <input type="number" className="form-control" value={ficha.estatura} onChange={set('estatura')} placeholder="170" />
              </div>
              <div className="form-group">
                <label>Peso (kg)</label>
                <input type="number" className="form-control" value={ficha.peso} onChange={set('peso')} placeholder="70" />
              </div>
              <div className="form-group">
                <label>Grupo sanguíneo</label>
                <select className="form-control" value={ficha.grupoSanguineo} onChange={set('grupoSanguineo')}>
                  <option value="">Selecciona...</option>
                  {['0+','0-','A+','A-','B+','B-','AB+','AB-'].map(g => <option key={g}>{g}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label>Presión arterial</label>
                <input className="form-control" value={ficha.presionArterial} onChange={set('presionArterial')} placeholder="120/80 mmHg" />
              </div>
              <div className="form-group">
                <label>Frecuencia cardíaca</label>
                <input className="form-control" value={ficha.frecuenciaCardiaca} onChange={set('frecuenciaCardiaca')} placeholder="72 bpm" />
              </div>
              <div className="form-group">
                <label>Glucosa en sangre</label>
                <input className="form-control" value={ficha.glucosa} onChange={set('glucosa')} placeholder="90 mg/dL" />
              </div>
            </div>
            {imc && (
              <div className="alert alert-info">
                📊 Tu IMC es <strong>{imc}</strong> — {imcLabel}
              </div>
            )}
          </>
        )}

        {/* TAB 2: Información médica */}
        {tab === 2 && (
          <>
            <div className="form-group">
              <label>Alergias conocidas</label>
              <input className="form-control" value={ficha.alergias} onChange={set('alergias')} placeholder="Ej: Penicilina, Ibuprofeno, Polen (separados por coma)" />
            </div>
            <div className="form-group">
              <label>Condiciones crónicas</label>
              <input className="form-control" value={ficha.condicionesCronicas} onChange={set('condicionesCronicas')} placeholder="Ej: Hipertensión, Diabetes tipo 2" />
            </div>
            <div className="form-group">
              <label>Medicamentos actuales</label>
              <input className="form-control" value={ficha.medicamentosActuales} onChange={set('medicamentosActuales')} placeholder="Ej: Metformina 500mg, Enalapril 10mg" />
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label>Cirugías previas</label>
                <textarea className="form-control" value={ficha.cirugiasPrevias} onChange={set('cirugiasPrevias')} placeholder="Ej: Apendicectomía (2015)" />
              </div>
              <div className="form-group">
                <label>Antecedentes familiares</label>
                <textarea className="form-control" value={ficha.antecedentesFamiliares} onChange={set('antecedentesFamiliares')} placeholder="Ej: Padre con diabetes, madre con hipertensión" />
              </div>
              <div className="form-group">
                <label>Hábito tabaco</label>
                <select className="form-control" value={ficha.habitoTabaco} onChange={set('habitoTabaco')}>
                  <option>No fumador</option>
                  <option>Ex fumador</option>
                  <option>Fumador ocasional</option>
                  <option>Fumador frecuente</option>
                </select>
              </div>
              <div className="form-group">
                <label>Consumo de alcohol</label>
                <select className="form-control" value={ficha.habitoAlcohol} onChange={set('habitoAlcohol')}>
                  <option>No consume</option>
                  <option>Ocasional</option>
                  <option>Moderado</option>
                  <option>Frecuente</option>
                </select>
              </div>
            </div>
          </>
        )}

        {/* TAB 3: Emergencia */}
        {tab === 3 && (
          <div className="grid-2">
            <div className="form-group">
              <label>Nombre completo</label>
              <input className="form-control" value={ficha.emergenciaNombre} onChange={set('emergenciaNombre')} placeholder="María Pérez" />
            </div>
            <div className="form-group">
              <label>Teléfono</label>
              <input className="form-control" value={ficha.emergenciaTelefono} onChange={set('emergenciaTelefono')} placeholder="+56 9 8765 4321" />
            </div>
            <div className="form-group">
              <label>Relación</label>
              <select className="form-control" value={ficha.emergenciaRelacion} onChange={set('emergenciaRelacion')}>
                <option>Familiar</option>
                <option>Cónyuge</option>
                <option>Pareja</option>
                <option>Amigo/a</option>
                <option>Otro</option>
              </select>
            </div>
          </div>
        )}

        <div style={{ display: 'flex', gap: 12, marginTop: 16 }}>
          <button className="btn btn-primary" onClick={handleGuardar} disabled={saving}>
            {saving ? 'Guardando...' : '💾 Guardar cambios'}
          </button>
          {tab < TABS.length - 1 && (
            <button className="btn btn-ghost" onClick={() => setTab(tab + 1)}>
              Siguiente →
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
